mapper.select:
SELECT id, ticket_id, pipeline_definition_id, status, started_at, completed_at, error_message, trace_parent, parameters_json, context_json, created_at
FROM pipeline_execution
WHERE id = #{id}

mapper.update:
UPDATE pipeline_execution
SET status = #{status},
    completed_at = #{completedAt},
    error_message = #{errorMessage}
WHERE id = #{id}

UPDATE pipeline_execution
SET context_json = #{contextJson}
WHERE id = #{id}
